INSERT INTO public.photos VALUES (24652, 'Casa de los Lazâ”œÃ­n c.1947', 'Imagen parcial del gran patio interior de la antigua casa de los Lazâ”œÃ­n, desde 1890 usufructuado por la Hijas de la Caridad de San Vicente de Paâ”œâ•‘l, y centrada en las escaleras de acceso al Asilo de la Coronaciâ”œâ”‚n de la Virgen del Pilar, fundado en 1909 por el cardenal Soldevila, para niâ”œâ–’os marginados y excluidos. Cuando las condiciones materiales del antiguo palacio ya no den mâ”œÃ­s de sâ”œÂ¡ (poco despuâ”œÂ®s de esta captura visual), y requieran una intervenciâ”œâ”‚n restauradora importante, el usufructo del edificio fue cedido a los herededos legales. Este espacio interior, luego, ha mutado a otra cosa. En la imagen, y a la izquierda, posiblemente el acceso desde la calle de Palafox, antigua del General del Reino. Fuente visual: foto Juan Mora Insa, en AHPZ.', 1947, 1947, 1947, 'Anos 40', 'CASCO HISTâ”œÃ´RICO', 41.65419800, -0.87476300, '0101000020E6100000F20698F90EFEEBBFE78D93C2BCD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32640854293.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32640854293.webp', 'https://www.flickr.com/photos/zaragozaantigua/32640854293/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24770, 'Ribera del Ebro 1977', 'Durante los prodigiosos aâ”œâ–’os del verticalismo y desarrollismo de los sesenta-setenta del siglo XX, con el ladrillo, el hormigâ”œâ”‚n y la especulaciâ”œâ”‚n desatada como seâ”œâ–’as de identidad, la ciudad fue objeto de una transformaciâ”œâ”‚n festejada en publirreportajes, no-dos, y preciosas postales que mostraban una nueva cara urbana moderna, avanzada, lustrosa, y joven. La construcciâ”œâ”‚n de infraestructuras y edificaciones de nueva planta, amâ”œÂ®n de la ingente demoliciâ”œâ”‚n y piqueteo de inmuebles viejos, generaron un Everest de residuos que fueron gestionados a la brava, sin molestas perturbaciones legislativas, o polâ”œÂ¡ticas pâ”œâ•‘blicas, que trabaran el progreso. Tonelada tras tonelada, las riberas fluviales y la periferia periurbana fueron recrecidas en altura, y cientos de miles de deposiciones con cascotes de obra se convirtieron en la nueva especie dominante de esos parajes. En la imagen, captura del paisaje que mostraba la ribera del Ebro junto al Camino del Vado y la calle Lourdes. Al fondo, la ciudad de las torres catedralicias, tras el puente de hierros. Hubo un tiempo en que esto formaba parte del denominado "Soto del Caâ”œâ–’ar". Fuente visual: Archivo Pâ”œâ•‘blico Municipal, Gerardo Sancho Ramo.', 1977, 1977, 1977, 'Anos 70', 'CASCO HISTâ”œÃ´RICO', 41.65502200, -0.86585900, '0101000020E6100000FD4FFEEE1DB5EBBF8C14CAC2D7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21656419220.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21656419220.webp', 'https://www.flickr.com/photos/zaragozaantigua/21656419220/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25149, 'Puente de las Tenerâ”œÂ¡as 1887', '"Inauguraciâ”œâ”‚n del puente de las Tenerâ”œÂ¡as". Medalla de bronce conmemorativa de la colocaciâ”œâ”‚n de la primera piedra del "puente de las Tenerâ”œÂ¡as", el 7 de mayo de 1887. Este proyecto no comenzâ”œâ”‚ a realizarse hasta 1891, inaugurâ”œÃ­ndose en 1895 con el nombre de puente de Nuestra Seâ”œâ–’ora del Pilar, mâ”œÃ­s conocido como de Hierro. Fuente visual: www.todocoleccion.net/', 1887, 1887, 1887, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65546400, -0.87088500, '0101000020E6100000757632384ADEEBBF49DA8D3EE6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31030640815.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31030640815.webp', 'https://www.flickr.com/photos/zaragozaantigua/31030640815/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25160, 'Calle Monserrate aâ”œâ–’os 30', 'Acuarela de Ambrosio Ruste. Calle de Monserrate, que unâ”œÂ¡a la del Sepulcro con la ribera del Ebro. Fuente: Lâ”œÃ­minas de A. Ruste. Ayuntamiento de Zaragoza, 1977.', 1930, 1930, 1939, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65485800, -0.87329700, '0101000020E6100000B83CD68C0CF2EBBF11C30E63D2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32062439830.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32062439830.webp', 'https://www.flickr.com/photos/zaragozaantigua/32062439830/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25168, 'Calle Retiro aâ”œâ–’os 30', 'Acuarela de Ambrosio Ruste. Confluencia de las calles del Retiro y del Garro (a la izquierda). Estas callejas se situarâ”œÂ¡an hoy en el entorno de la calle del Boterâ”œâ”‚n. Fuente: Lâ”œÃ­minas de A. Ruste. Ayuntamiento de Zaragoza, 1977.', 1930, 1930, 1939, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65445700, -0.87324300, '0101000020E6100000ECBFCE4D9BF1EBBFB3D1393FC5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32440628885.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32440628885.webp', 'https://www.flickr.com/photos/zaragozaantigua/32440628885/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25182, 'Puente de las Tenerâ”œÂ¡as 1887', 'Grabado basado en una fotografâ”œÂ¡a que ilustra la ceremonia de colocaciâ”œâ”‚n de la primera piedra del nuevo puente de las Tenerâ”œÂ¡as sobre el râ”œÂ¡o Ebro, el 7 de mayo de 1887. La escena tiene lugar en el punto de arranque del primer estribo del nuevo puente en el barrio de las Tenerâ”œÂ¡as, en el tramo de la ribera comprendido entre las puertas del â”œÃ¼ngel y del Sol. A este lugar todavâ”œÂ¡a se lo denominaba como de "Los Maderos", una reminiscencia del puente de Tablas o de Madera desaparecido en los albores del siglo. La ceremonia se desarrolla a primera hora de la tarde, con presencia del ministro de Fomento, Carlos Navarro Rodrigo, ademâ”œÃ­s de la Corporaciâ”œâ”‚n municipal, encabezada por su alcalde-presidente Simâ”œâ”‚n Sâ”œÃ­inz de Varanda, representantes de la Diputaciâ”œâ”‚n provincial y nutrida parroquia de pâ”œâ•‘blico asistente. Al fondo de la imagen, la margen izquierda, con el molino de harina, un lavadero y la Torre de Sala. Tras ellos deberâ”œÂ¡a despuntar la torre del antiguo convento de Jesâ”œâ•‘s, pero no lo hace. Este puente, como es usual en la ciudad, tiene una buena relaciâ”œâ”‚n de nombres que lo identifican: nuevo sobre el Ebro, de las Tenerâ”œÂ¡as, de la Virgen del Pilar, de Nuestra seâ”œâ–’ora del Pilar, y de Hierro, que suele ser la mâ”œÃ­s extendida y funcional.', 1887, 1887, 1887, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65426800, -0.87173900, '0101000020E610000052BAF42F49E5EBBFE068C70DBFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49822067107.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49822067107.webp', 'https://www.flickr.com/photos/zaragozaantigua/49822067107/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25414, 'Ampliaciâ”œâ”‚n Puente de Hierro 1990', 'Vicente Modesto Locual. 1990 Desde 1895 el Puente de Hierro era uno uno de los principales accesos a la ciudad desde el norte (incluso tras la construcciâ”œâ”‚n del puente de Santiago), muy mayoritariamente para el gran anarquizante y devorador de espacios pâ”œâ•‘blicos que es el vehâ”œÂ¡culo privado. En la â”œâ•‘ltima dâ”œÂ®cada del XX, el puente es profundamente remodelado bajo direcciâ”œâ”‚n de Javier Manterola: la estructura metâ”œÃ­lica se repara, limpia y pinta, y se le aâ”œâ–’aden dos tableros laterales en forma de arco para derivar por ellos el paso de vehâ”œÂ¡culos. La plataforma central se reserva para uso peatonal, ese gran desconocido del urbanismo desarrollista y postdesarrollista franquista. La remodelaciâ”œâ”‚n finalizâ”œâ”‚ en 1991. En la imagen, aâ”œÂ®rea visual desde la margen izquierda de la implementaciâ”œâ”‚n de los tableros laterales. Desde ese punto de vista, a la izquierda, estado de la ribera con las instalaciones fabriles de Pikolâ”œÂ¡n. En la otra orilla, a la derecha, la plaza de San Bruno sin las nuevas viviendas protegidas y, lâ”œâ”‚gicamente, convertida en aparcamiento en superficie.', 1990, 1990, 1990, 'Anos 90', 'CASCO HISTâ”œÃ´RICO', 41.65590700, -0.87050700, '0101000020E6100000E10CFE7E31DBEBBFD61BB5C2F4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15182757080.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15182757080.webp', 'https://www.flickr.com/photos/zaragozaantigua/15182757080/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25434, 'Puente de Hierro 2011', 'Foto: Oliver Duch. Singular instantâ”œÃ­nea tomada desde el puente de Nuestra Seâ”œâ–’ora del Pilar o de Hierro, el jueves 13 de octubre de 2011, al paso de la maqueta en cristal o "farol" de la basâ”œÂ¡lica del Pilar, con ella detrâ”œÃ­s. Esta confluencia se dio, por primera vez, por el desvâ”œÂ¡o del Rosario de Cristal a causa de las obras del tranvâ”œÂ¡a. Participaron en la procesiâ”œâ”‚n las mâ”œÃ­ximas autoridades en plaza: Luisa Fernanda Rudi, presidenta del Gobierno de Aragâ”œâ”‚n; Luis Marâ”œÂ¡a Beamonte, presidente de la Diputaciâ”œâ”‚n Provincial; y Juan Alberto Belloch, alcalde de Zaragoza. Fuente: Heraldo de Aragâ”œâ”‚n.', 2011, 2011, 2011, 'Siglo XXI', 'CASCO HISTâ”œÃ´RICO', 41.65532300, -0.87140600, '0101000020E6100000BD38F1D58EE2EBBF87A8C29FE1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24763765578.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24763765578.webp', 'https://www.flickr.com/photos/zaragozaantigua/24763765578/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25442, 'Puente de Hierro 1991', 'Imagen capturada durante las pruebas de carga al final de las obras de ampliaciâ”œâ”‚n del puente de Hierro, denominada "abrazo del Ebro" por el amable acompaâ”œâ–’amiento de los dos nuevos viales para circulaciâ”œâ”‚n rodada, uno en cada direcciâ”œâ”‚n, al antiguo puente, cuyo uso fue reservado a viandantes, bicicletas, y animales irracionales. La toma se ha realizado desde las torres edilicias inmediatas al puente en la margen izquierda. Al otro lado del râ”œÂ¡o, visual del colegio de las Tenerâ”œÂ¡as, y a su izquierda, el solar sobre el que mâ”œÃ­s tarde se construirâ”œÂ¡a el Pabellâ”œâ”‚n Deportivo Municipal de las Tenerâ”œÂ¡as, el Centro de Salud de la Rebolerâ”œÂ¡a, y algunas nuevas viviendas recayentes a la antigua calle del Râ”œÂ¡o. A la derecha, la glorieta donde estuviera la antigua Portaza, luego puerta del Sol. Fuente visual: "Asociaciâ”œâ”‚n de Vecinos Barrio de Jesâ”œâ•‘s. 30 aâ”œâ–’os de Historia".', 1991, 1991, 1991, 'Anos 90', 'CASCO HISTâ”œÃ´RICO', 41.65554800, -0.87099000, '0101000020E6100000C993A46B26DFEBBFA77A32FFE8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30532659566.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30532659566.webp', 'https://www.flickr.com/photos/zaragozaantigua/30532659566/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25450, 'Puente de Hierro 1990', 'Imagen capturada durante las obras de ampliaciâ”œâ”‚n del puente de Hierro mediante el aâ”œâ–’adido de dos tableros laterales en forma de arco por los que derivar el paso de la circulaciâ”œâ”‚n rodada (uno de ellos, a la derecha), mientras que la plataforma central, el histâ”œâ”‚rico puente (izquierda), se reservâ”œâ”‚ para uso peatonal. En la imagen, tomada desde la margen derecha, y al fondo, destacan algunas de las instalaciones de la antigua fâ”œÃ­brica de colchones de Alfonso Solans, en la antigua calle del puente del Pilar, luego redenominada en homenaje a este local prâ”œâ”‚cer. Detrâ”œÃ­s, en el camino del Vado, puede verse el colegio de la Purâ”œÂ¡sima y San Antonio. Fuente visual: archivo Heraldo de Aragâ”œâ”‚n, en "Padre Ebro. El râ”œÂ¡o Ebro y el siglo XX".', 1990, 1990, 1990, 'Anos 90', 'CASCO HISTâ”œÃ´RICO', 41.65546400, -0.87088500, '0101000020E6100000757632384ADEEBBF49DA8D3EE6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33960709815.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33960709815.webp', 'https://www.flickr.com/photos/zaragozaantigua/33960709815/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25458, 'Puente de Hierro 1990', 'Imagen capturada en el arranque del puente de Hierro o de Nuestra Seâ”œâ–’ora del Pilar desde la margen izquierda durante las obras de remodelaciâ”œâ”‚n que, bajo la direcciâ”œâ”‚n de Javier Manterola, repararon la estructura del puente inaugurado en 1895, y se le aâ”œâ–’adieron dos tableros laterales en forma de arco para derivar por ellos el trâ”œÃ­nsito rodado. La plataforma central fue reservada para uso peatonal. En primer tâ”œÂ®rmino, detalle del antiguo adoquinado del puente al descubierto por el desgaste de la superficial capa de asfalto a causa del intenso trâ”œÃ­fico.', 1990, 1990, 1990, 'Anos 90', 'CASCO HISTâ”œÃ´RICO', 41.65648100, -0.87022600, '0101000020E6100000EB1F4432E4D8EBBF02B9C49107D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50308819236.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50308819236.webp', 'https://www.flickr.com/photos/zaragozaantigua/50308819236/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25459, 'Puente de Hierro 1990', 'Imagen capturada durante la remodelaciâ”œâ”‚n del puente de Nuestra Seâ”œâ–’ora del Pilar o de Hierro, que proyectada por el arquitecto Javier Manterola incluâ”œÂ¡a dos tableros laterales en forma de arco para el paso de vehâ”œÂ¡culos. Aquâ”œÂ¡ figura el tablero occidental, tras el que al fondo y en la margen izquierda destacan los bloques de viviendas de las calles de Cecilio Navarro, Nicolâ”œÃ­s de Funes y de Jesâ”œâ•‘s, recayentes a la homâ”œâ”‚nima plaza.', 1990, 1990, 1990, 'Anos 90', 'CASCO HISTâ”œÃ´RICO', 41.65539000, -0.87129900, '0101000020E61000003C33C170AEE1EBBF0E10CCD1E3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50460967823.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50460967823.webp', 'https://www.flickr.com/photos/zaragozaantigua/50460967823/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25531, 'Ribera del Ebro c.1966', 'Fototeca Universidad de Sevilla. Aâ”œâ–’os 60. "Vista de Zaragoza". Imagen capturada desde la ribera izquierda del Ebro, entre el Puente del Pilar, o de Hierro, y el antiguo Molino de San Lâ”œÃ­zaro, en un espacio entonces ocupado por lo que vemos. Al fondo, la soledad del enorme bloque 47-49 de San Vicente de Paâ”œâ•‘l (construido en 1954), y la fachada al Ebro de la Seo, el Palacio Arzobispal, la Lonja, el nuevo Ayuntamiento, y el Pilar. Fuente visual: fototeca.us.es/imagen.jsp?id=43768&tipo=v&elto=0&...', 1966, 1966, 1966, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65658600, -0.87148500, '0101000020E6100000C18BBE8234E3EBBF778192020BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15644187735.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15644187735.webp', 'https://www.flickr.com/photos/zaragozaantigua/15644187735/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
