INSERT INTO public.photos VALUES (25547, 'Vista Râ”œÂ¡o Ebro 1932', 'Desde el puente del Pilar, imagen panorâ”œÃ­mica de la ciudad, el râ”œÂ¡o Ebro y el puente de Piedra. A la izquierda, la fachada del paseo de la Ribera, desde el convento del Sepulcro, y las ruinas del estribo en piedra del antiguo puente de Tablas, pasando por la Seo, el palacio Esmir y el palacio Arzobispal, hasta el Pilar. A la derecha, la arboleda de Macanaz. Composiciâ”œâ”‚n inâ”œÂ®dita, democrâ”œÃ­tica, cientâ”œÂ¡fica y popular, generada en los laboratorios del', 1932, 1932, 1932, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65580700, -0.87212500, '0101000020E61000009CC420B072E8EBBF73BED87BF1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23224165536.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23224165536.webp', 'https://www.flickr.com/photos/zaragozaantigua/23224165536/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25549, 'Ebro c.1909', 'Desde el puente de Hierro una interesante vista hacia el râ”œÂ¡o Ebro y el puente de Piedra, con restos, a la derecha, del conglomerado pâ”œÂ®treo, o estribo, sobre el que descansaba el acceso del antiguo puente de Tablas a la margen izquierda. A su lado, el que fuera Molino de San Lâ”œÃ­zaro, ya en su dieciochesca ubicaciâ”œâ”‚n. Fuente visual: Estudio Coyne (DARA-AHPZ)', 1909, 1909, 1909, 'Anos 1900', 'CASCO HISTâ”œÃ´RICO', 41.65653600, -0.87131900, '0101000020E610000002452C62D8E1EBBFC652245F09D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23884124486.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23884124486.webp', 'https://www.flickr.com/photos/zaragozaantigua/23884124486/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25550, 'Puente de Hierro 1975', 'Turbamulta de baâ”œâ–’istas haciendo uso, en sus diversas modalidades, de una de las domâ”œÂ®sticas playas del râ”œÂ¡o Ebro en su domesticado paso estival por la ciudad. Esta era la tradicional "Playa de las Hojalatas", cariâ”œâ–’oso apodo por la simpâ”œÃ­tica y metâ”œÃ­lica proliferaciâ”œâ”‚n de recipientes (usados) elaborados en hoja de lata, en el pedazo de ribera aledaâ”œâ–’a al entronque del puente del Pilar, o de Hierro, en la margen derecha. Al fondo, el torreado receptâ”œÃ­culo de Nâ”¬Â¬ Sâ”¬Â¬ del Pilar, y el puente de Piedra. Un trolebâ”œâ•‘s de la lâ”œÂ¡nea del "Gâ”œÃ­llego" transita por el puente, camino del Gâ”œÃ­llego, unos meses antes de ser desmantelada por el progreso y los autobuses a â”œÂ®l asociados. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1975, 1975, 1975, 'Anos 70', 'CASCO HISTâ”œÃ´RICO', 41.65453500, -0.87085800, '0101000020E61000000FB8AE9811DEEBBF2F8B89CDC7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24223990960.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24223990960.webp', 'https://www.flickr.com/photos/zaragozaantigua/24223990960/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25551, 'Vista desde la Seo 1906', 'Vista desde la torre de la Seo del râ”œÂ¡o Ebro, en su crecida de 1906, con el puente de Hierro y el detalle del abigarrado caserâ”œÂ¡o cercano a la ribera, entre la catedral y el Coso Bajo. Al fondo se puede leer el cartel de "Maderas Nicolâ”œÃ­s Hermanos". Fuente: www.zaragoza.es/contenidos/medioambiente/.../otros/catalo...', 1906, 1906, 1906, 'Anos 1900', 'CASCO HISTâ”œÃ´RICO', 41.65452200, -0.87358600, '0101000020E610000064CA87A06AF4EBBF9A417C60C7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24314983084.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24314983084.webp', 'https://www.flickr.com/photos/zaragozaantigua/24314983084/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25552, 'Vista Ebro 1907', 'Foto: Petit. Vista de la margen derecha del râ”œÂ¡o Ebro a su paso por Zaragoza, tomada desde el puente del Pilar en el otoâ”œâ–’o de 1907. A la izquierda, restos del estribo sobre el que se asentaba el antiguo puente de Tablas de la ciudad. Fuente: Ministâ”œÂ¿re de la Culture (France) - Mâ”œÂ®diathâ”œÂ¿que de l''architecture et du patrimoine.', 1907, 1907, 1907, 'Anos 1900', 'CASCO HISTâ”œÃ´RICO', 41.65554800, -0.87099000, '0101000020E6100000C993A46B26DFEBBFA77A32FFE8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24571307164.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24571307164.webp', 'https://www.flickr.com/photos/zaragozaantigua/24571307164/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25556, 'Vista desde el Ebro 1907', 'Foto: Petit. Vista de Zaragoza desde la margen izquierda del râ”œÂ¡o Ebro en el otoâ”œâ–’o de 1907. A la derecha, restos del estribo sobre el que se asentaba el antiguo puente de Tablas de la ciudad. Fuente: Ministâ”œÂ¿re de la Culture (France) - Mâ”œÂ®diathâ”œÂ¿que de l''architecture et du patrimoine.', 1907, 1907, 1907, 'Anos 1900', 'CASCO HISTâ”œÃ´RICO', 41.65653600, -0.87131900, '0101000020E610000002452C62D8E1EBBFC652245F09D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25108644621.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25108644621.webp', 'https://www.flickr.com/photos/zaragozaantigua/25108644621/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25560, 'Râ”œÂ¡o Ebro 1910', 'Foto: Charles Jacquin. Placa autocroma de una vista de Zaragoza desde la margen izquierda del râ”œÂ¡o Ebro y a espaldas del puente de N.â”¬Â¬ S.â”¬Â¬ del Pilar. En primer tâ”œÂ®rmino y a la derecha, restos del estribo norte del antiguo puente de Tablas donde terminaba el homâ”œâ”‚nimo camino que conectaba con la calle de Jesâ”œâ•‘s, junto al lavadero de Modesto Andrâ”œÂ®s. Detrâ”œÃ­s de este estribo se encontraba el antiguo molino de sal de San Lâ”œÃ­zaro alimentado por la acequia del Rabal, que desde 1907 funcionaba como molino harinero del Puente de Tablas accionado ademâ”œÃ­s por un motor elâ”œÂ®ctrico, lo que le permitâ”œÂ¡a moler el grano Ã”Ã‡Â£a cualquier hora del dâ”œÂ¡a y en toda â”œÂ®pocaÃ”Ã‡Ã˜. Al fondo, el puente de Piedra donde destaca el aspecto de su tercera pila, con bloques de piedra sobre su baja estructura. Por encima suyo, aspecto de la fachada al râ”œÂ¡o del tramo edilicio entre el Seminario y el templo del Pilar. Fuente visual: bibliotheques-specialisees.paris.fr/', 1910, 1910, 1910, 'Anos 10', 'CASCO HISTâ”œÃ´RICO', 41.65653600, -0.87131900, '0101000020E610000002452C62D8E1EBBFC652245F09D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/28396195976.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/28396195976.webp', 'https://www.flickr.com/photos/zaragozaantigua/28396195976/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25566, 'Râ”œÂ¡o Ebro 1910', 'Placa autocroma de una vista capturada desde el puente de Hierro, con interesante visual del râ”œÂ¡o Ebro, el puente de Piedra, restos del estribo sur del antiguo puente de Tablas, y el correspondiente tramo de la margen derecha. Al fondo, la torre de la Seo y las dos del Pilar. Fuente visual: Charles Jacquin photographe bibliotheques-specialisees.paris.fr/', 1910, 1910, 1910, 'Anos 10', 'CASCO HISTâ”œÃ´RICO', 41.65560300, -0.87195100, '0101000020E610000027DD96C805E7EBBF6A1492CCEAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32935866406.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32935866406.webp', 'https://www.flickr.com/photos/zaragozaantigua/32935866406/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25575, 'Râ”œÂ¡o Ebro 1909', 'Imagen capturada en la margen izquierda, donde la playa de cantos rodados a espaldas del lavadero de la calle de Jesâ”œâ•‘s inmediato al puente de N.â”¬Â¬ S.â”¬Â¬ del Pilar, con una interesante vista del râ”œÂ¡o Ebro con el fondo del tramo de la margen derecha con el que confrontaba. En la orilla y al fondo a la izquierda destacan los restos del estribo del antiguo puente de Tablas o Madera. Tras el arbolado paseo del Ebro, edificios comprendidos entre â”œÂ®ste y las calles de Monserrate, Grillo, Silencio y Conde de Alperche, en cuyos bajos se abrâ”œÂ¡an varios establecimientos de construcciâ”œâ”‚n y alquiler de carros, ademâ”œÃ­s de tratantes de caballerâ”œÂ¡as. A continuaciâ”œâ”‚n, la gran casa que fuera de los Esmir (donde emerge al fondo el cimborrio de la Seo), seguida por el palacio Arzobispal (donde destaca la barroca torre de la Seo).', 1909, 1909, 1909, 'Anos 1900', 'CASCO HISTâ”œÃ´RICO', 41.65614400, -0.87287600, '0101000020E610000052D32EA699EEEBBFBABBCE86FCD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52235254996.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52235254996.webp', 'https://www.flickr.com/photos/zaragozaantigua/52235254996/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25996, 'Vista Puente Hierro c.1942', 'Vista aâ”œÂ®rea de la zona del Puente del Pilar, o de Hierro. En la margen derecha, visual del edificio de la Serrerâ”œÂ¡a Nicolâ”œÃ­s (a la derecha del jardâ”œÂ¡n triangular) y el complejo de los edificios de nuevo y ribereâ”œâ–’o Cuartel de Automovilismo. En la margen izquierda, el Barrio de Jesâ”œâ•‘s, los enormes lavaderos de Modesto Andrâ”œÂ®s, y el cuartel de San Lâ”œÃ­zaro.', 1942, 1942, 1942, 'Anos 40', 'CASCO HISTâ”œÃ´RICO', 41.65554800, -0.87099000, '0101000020E6100000C993A46B26DFEBBFA77A32FFE8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20892928843.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20892928843.webp', 'https://www.flickr.com/photos/zaragozaantigua/20892928843/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (26010, 'Vista aâ”œÂ®rea 2006', 'Foto: Juan Carlos Arcos. Panorâ”œÃ­mica de Zaragoza desde el paseo de Echegaray y Caballero, con parte de las instalaciones de la fâ”œÃ­brica de armamento Instalaza, a la izquierda. A la derecha, antes del puente de Hierro aâ”œâ•‘n sin pintar de azul, el reciâ”œÂ®n creado parque ribereâ”œâ–’o que serâ”œÃ­ desmantelado poco despuâ”œÂ®s para hacer otro similar, en un ejercicio de lucrativo quita y pon propio del perâ”œÂ¡odo. Fuente: Heraldo de Aragâ”œâ”‚n, 18 de junio de 2006.', 2006, 2006, 2006, 'Siglo XXI', 'CASCO HISTâ”œÃ´RICO', 41.65381700, -0.86929500, '0101000020E6100000377172BF43D1EBBFCF488446B0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22299638391.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22299638391.webp', 'https://www.flickr.com/photos/zaragozaantigua/22299638391/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (26050, 'Vista panorâ”œÃ­mica c.1904', 'Postal panorâ”œÃ­mica coloreada que muestra la margen derecha del râ”œÂ¡o Ebro, desde el puente del Pilar hasta el de Piedra. Se distinguen las torres de San Nicolâ”œÃ­s, la Magdalena, la Seo y el Pilar. Fuente: www.todocoleccion.net', 1904, 1904, 1904, 'Anos 1900', 'CASCO HISTâ”œÃ´RICO', 41.65607300, -0.87354600, '0101000020E6100000D7A6B1BD16F4EBBFF1643733FAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32022513125.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32022513125.webp', 'https://www.flickr.com/photos/zaragozaantigua/32022513125/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21020, 'San Pablo &quot;antigua mezquita&quot; 1869', 'Tomando como referencia un dibujo de Genaro Pâ”œÂ®rez de Villa-Amil realizado la dâ”œÂ®cada anterior, la revista "El Museo Universal" en su nâ”œâ•‘mero 46 (14-XI-1869) publicâ”œâ”‚ esta ilustraciâ”œâ”‚n con un intrigante pie de imagen que asevera que la iglesia parroquial de San Pablo fue "antigua mezquita". El cuerpo del texto del reportaje ahonda mâ”œÃ­s en el misterio, al apuntar "un carâ”œÃ­cter oriental, imposible de confundir con ningun (sic) otro estilo arquitectâ”œâ”‚nico", que despojado "de los revestimientos modernos" muestra "las lâ”œÂ¡neas magistrales de la ya purificada mezquita". Por supuesto, mezquita, o no, la dataciâ”œâ”‚n cronolâ”œâ”‚gica sigue siendo la canâ”œâ”‚nica cristiana: comienzos del siglo XII, tras la conquista cristiana, cuando en pocos aâ”œâ–’os, y por arte de "birlibirloque", Saragoâ”œÂºa se convirtiâ”œâ”‚, segâ”œâ•‘n los grandes estudiosos locales del arte cristiano, en el nâ”œâ•‘cleo mâ”œÃ­s densamente poblado por iglesias, parroquias y ermitas româ”œÃ­nicas de nueva planta de todo el occidente cristiano europeo, en paralelo a la fantâ”œÃ­stica desapariciâ”œâ”‚n de todos los edificios religiosos de la Saraqusta musulmana que habâ”œÂ¡an prestado servicio durante los 400 aâ”œâ–’os anteriores. No obstante, cuando siglos despuâ”œÂ®s se ha procedido a restaurar algunos de estos edificios "româ”œÃ­nicos", no se han detectado apenas trazas româ”œÃ­nicas de relieve, y sâ”œÂ¡, de siglos anteriores. El texto apunta una posibilidad menos delirante, cuando introduce el concepto "purificada mezquita": mediante ceremoniales rituales, se despoja a un edificio o estructura de sus efluvios moriscos, y se le reconvierte en un edificio cristiano "de toda la vida". Una aplicaciâ”œâ”‚n del arte de reciclar y reutilizar, "avant la lettre", que fue aplicado cientâ”œÂ¡ficamente en esta ciudad, comenzando por su referencial Mezquita Aljama construida por Hanas ibn cAbd Allah as-Sancâ”œÃ­ni, y ampliada luego, que tras su "purificaciâ”œâ”‚n" serâ”œÃ­ denominada por los invasores cristianos como "Seo de San Salvador". Esta nueva versiâ”œâ”‚n del dibujo muestra algunas variaciones respecto del original, com', 1869, 1869, 1869, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65613400, -0.88619500, '0101000020E6100000791EDC9DB55BECBF97E5EB32FCD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19921997159.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19921997159.webp', 'https://www.flickr.com/photos/zaragozaantigua/19921997159/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21033, 'Plaza del Mercado 1868', 'Plaza del Mercado capturada desde la altura de las calles Cerdâ”œÃ­n y Escuelas Pâ”œÂ¡as. Al fondo, la calle de Antonio Pâ”œÂ®rez, conducente a la puerta de San Ildefonso y el paseo del Ebro. De la macizada manzana entre la plaza de San Antâ”œâ”‚n y San Juan de los Panetes emerge la Zuda. Fuente visual: Frank Mason Good, en la exposiciâ”œâ”‚n ''Zaragoza estereoscâ”œâ”‚pica. Fotografâ”œÂ¡a profesional y comercial''', 1868, 1868, 1868, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65614200, -0.88307000, '0101000020E6100000E08442041C42ECBF1AC40776FCD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26477064146.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26477064146.webp', 'https://www.flickr.com/photos/zaragozaantigua/26477064146/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21042, 'Procesiâ”œâ”‚n del Pilar 1860', 'Dibujo de la procesiâ”œâ”‚n de la Virgen del Pilar realizada la desapacible tarde del 12 de octubre e inmortalizada pues tuvo como partâ”œÂ¡cipes a la reina Isabel II, al rey Francisco de Asâ”œÂ¡s de Borbâ”œâ”‚n, y al prâ”œÂ¡ncipe de Asturias Alfonso de Borbâ”œâ”‚n, ya que coincidiâ”œâ”‚ con su viaje oficial a Zaragoza realizado ese aâ”œâ–’o. Esta nutrida procesiâ”œâ”‚n saliâ”œâ”‚ del templo del Pilar y recorriâ”œâ”‚ las câ”œÂ®ntricas calles de la Sombrererâ”œÂ¡a, de la Virgen y del Arco de Toledo, la plaza del Mercado, las calles de la Albarderâ”œÂ¡a y del Coso, la plaza de la Constituciâ”œâ”‚n, las calles de San Gil, de San Pedro, de la Virgen del Rosario, de la Cuchillerâ”œÂ¡a, del Pilar, hasta desembocar en la plaza del Pilar. En el dibujo destaca la imagen en plata de la Virgen del Pilar precedida de los Infanticos y conducida en andas entre las filas de canâ”œâ”‚nigos que portan el palio. Siguen despuâ”œÂ®s los concejales precedidos de los maceros municipales, las autoridades de la Diputaciâ”œâ”‚n provincial y la familia Real. La Reina destaca con traje cubierto de encajes blancos y la corona real sobre sus sienes. Junto a ella, el Rey vestido en uniforme de Capitâ”œÃ­n general del Ejâ”œÂ®rcito. En el Gran Archivo Zaragoza Antigua (GAZA) ubicamos este dibujo, posiblemente, en la plaza del Mercado. Fuente visual: dibujo y litografâ”œÂ¡a de Vicente Urrabieta realizada en el establecimiento litogrâ”œÃ­fico de Josâ”œÂ® Donâ”œâ”‚n (Madrid), aparecida en "Crâ”œâ”‚nica del viaje de sus Majestades Altezas reales a las Islas Baleares, Cataluâ”œâ–’a y Aragâ”œâ”‚n en 1860" (Antonio Flores Algovia, 1861), y coloreada en echosinhache.blogspot.com/', 1860, 1860, 1860, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65607400, -0.88306700, '0101000020E61000009CA8A5B91542ECBFC1E09A3BFAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/45402694302.webp', 'https://ktnavneugmimhdvpn