INSERT INTO public.photos VALUES (21197, 'Calle de las Escuelas Pâ”œÂ¡as c.1898', 'Imagen con la primera ubicaciâ”œâ”‚n productiva y comercial de la empresa Chocolates Orâ”œâ•‘s establecida por Joaquâ”œÂ¡n Orâ”œâ•‘s Abadâ”œÂ¡a en 1898 en el nâ”¬â•‘ 19 de la calle de las Escuelas Pâ”œÂ¡as, chaflanera con el nâ”¬â•‘ 2 de la calle de Basilio Boggiero (a la izquierda). Aquâ”œÂ¡ estuvo previamente la fâ”œÃ­brica de chocolates y tienda de ultramarinos de Pedro Gâ”œâ”‚mez, y en la imagen albergaba la factorâ”œÂ¡a de Orâ”œâ•‘s y el comercio La Abeja Colonial de Seuba&Carbonell.', 1898, 1898, 1898, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65491800, -0.88447400, '0101000020E61000009831056B9C4DECBFE7C75F5AD4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51334556070.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51334556070.webp', 'https://www.flickr.com/photos/zaragozaantigua/51334556070/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21295, 'Plaza del Mercado c.1900', 'Imagen de la antigua plaza del Mercado, capturada desde cierta altura en la manzana entre las calles de las Escuelas Pâ”œÂ¡as, y de Juan Jimâ”œÂ®nez Cerdâ”œÃ­n. El enfoque estâ”œÃ­ centrado en la fachada oriental de la plaza, comprendida entre los nâ”œâ•‘meros 41 (izquierda), junto a la calle Manifestaciâ”œâ”‚n, y 69 (derecha), junto a la calle de la Torre Nueva. Destacan los soportales entoldados, a nivel de calle, entre los que se instalaban los puestos del mercado. Esta fachada formaba parte de la manzana de viviendas entre la plaza del Mercado y la calle de Lanuza, en cuya zona central, longitudinalmente, y enmascarado por las viviendas, estaba localizado uno de los tramos de la antigua muralla de piedra de la ciudad. Sobre el firme aparece el trazado de la tranviaria lâ”œÂ¡nea "Circunvalaciâ”œâ”‚n", que ingresaba en la plaza por la calle de Cerdâ”œÃ­n. Poco tiempo despuâ”œÂ®s, esta manzana serâ”œÂ¡a integralmente derribada para iniciar la construcciâ”œâ”‚n del nuevo Mercado de la ciudad. Esta monumental imagen fue convertida por la Fototipia de Lucas Escolâ”œÃ­ en comercial postal de la serie "Zaragoza", con el nâ”œâ•‘mero 43, y titulada "Antiguo Mercado". Fuente visual: www.ebay.es/', 1900, 1900, 1900, 'Anos 1900', 'CASCO HISTâ”œÃ´RICO', 41.65584600, -0.88318800, '0101000020E61000005B07077B1343ECBF309B00C3F2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31215207052.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31215207052.webp', 'https://www.flickr.com/photos/zaragozaantigua/31215207052/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21471, 'San Pablo Apâ”œâ”‚stol 1912', 'Imagen de la iglesia parroquial de San Pablo Apâ”œâ”‚stol centrada en su singular atalaya.', 1912, 1912, 1912, 'Anos 10', 'CASCO HISTâ”œÃ´RICO', 41.65600800, -0.88620100, '0101000020E610000002D71533C25BECBF0AF5F411F8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53580689263.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53580689263.webp', 'https://www.flickr.com/photos/zaragozaantigua/53580689263/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21843, 'Calle Conde de Aranda 1933', 'Imagen capturada en el interior del nuevo Monumental Cinema poco antes de su inauguraciâ”œâ”‚n, cinematâ”œâ”‚grafo de la empresa de Hermâ”œâ”‚genes Herrero proyectado por el arquitecto Marcelo Carquâ”œÂ® con capacidad para 2319 personas. De estilo moderno, racionalista, y monumentales dimensiones, tenâ”œÂ¡a su entrada principal en la calle del Conde de Aranda nâ”¬â•‘ 32, y contaba con una salida en la calle de Boggiero nâ”¬â•‘ 47. Fue clausurado 39 aâ”œâ–’os despâ”œâ•£â”œÂ®s, y su enorme solar reurbanizado de forma bien provechosa. Fuente visual: www.mecd.gob.es/.', 1933, 1933, 1933, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65514400, -0.88703700, '0101000020E610000045F12A6B9B62ECBFD71533C2DBD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/35602884753.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/35602884753.webp', 'https://www.flickr.com/photos/zaragozaantigua/35602884753/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21846, 'Calle de Cerdâ”œÃ­n 1934', 'Imagen capturada en el tramo de la calle de Cerdâ”œÃ­n conducente al Mercado Central, y centrada en la modernâ”œÂ¡sima fachada (tras reciente reforma) de la gran zapaterâ”œÂ¡a Calzados el Siglo XX, de la viuda de Miguel Ferrer, que vio iniciar su actividad en las postrimerâ”œÂ¡as del siglo XIX. El tradicional y muy demandado gâ”œÂ®nero de las alpargatas y zapatillas tenâ”œÂ¡a un acceso propio desde la trasera calle de las Escuelas Pâ”œÂ¡as, junto a la entrada a la calle de San Pablo. Este establecimiento estaba especializado en un nuevo tipo de zapato para la seâ”œâ–’ora y el niâ”œâ–’o (sic) denominado "Checo". Sobre el firme, en primer tâ”œÂ®rmino, y hacia la derecha, tendido tranviario de la lâ”œÂ¡nea Ayuntamiento-Portillo, originalmente de la lâ”œÂ¡nea Circunvalaciâ”œâ”‚n como ramal plaza de la Constituciâ”œâ”‚n-Puente de Piedra por el Mercado. Fuente visual: www.mecd.gob.es/.', 1934, 1934, 1934, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65520000, -0.88392600, '0101000020E6100000EAB0C22D1F49ECBF6B2BF697DDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/35661297254.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/35661297254.webp', 'https://www.flickr.com/photos/zaragozaantigua/35661297254/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21854, 'Calle de Torre Nueva 1932', 'Imagen centrada en la gran fachada de la casa de los condes de Bureta en el nâ”¬â•‘ 6 de la calle de Torre Nueva cuando ya pendâ”œÂ¡a sobre ella la amenaza de derribo, algo que se consumarâ”œÂ¡a tres aâ”œâ–’os despuâ”œÂ®s. Ya en el siglo XV y cuando la calle se denominaba Nueva del Mercado, esta era la casa de los Lâ”œâ”‚pez de Villanova, que en el siglo XVII pasâ”œâ”‚ a los condes de Bureta. La original y tradicional fachada de la casona era en ladrillo caravista y culminaba en galerâ”œÂ¡a de arquillos y alero saliente. Fue revocada despuâ”œÂ®s en yeso, abriâ”œÂ®ndose grandes balcones y ventanales regulares, como la imagen ilustra. A la derecha del edificio, e inmediato, el acceso a la empinada calle de Antâ”œâ”‚n Trillo y a la plaza de Lanuza. Fuente visual: www.mecd.gob.es/.', 1932, 1932, 1932, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65533100, -0.88303200, '0101000020E610000080492A53CC41ECBF0987DEE2E1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/35882023093.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/35882023093.webp', 'https://www.flickr.com/photos/zaragozaantigua/35882023093/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21937, 'San Pablo aâ”œâ–’os 40', 'San Pablo, aguafuerte, Jesâ”œâ•‘s Fernâ”œÃ­ndez Barrio, Diputaciâ”œâ”‚n de Zaragoza, c. 1945-1947. Iglesia de San Pablo de Zaragoza. Fuente: web.dpz.es/arscatalogi.es/', 1940, 1940, 1949, 'Anos 40', 'CASCO HISTâ”œÃ´RICO', 41.65621600, -0.88624400, '0101000020E6100000D4D688601C5CECBF548EC9E2FED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15257156253.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15257156253.webp', 'https://www.flickr.com/photos/zaragozaantigua/15257156253/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22073, 'San Pablo 1953', 'Imagen de la puerta principal y la torre de la parroquia de San Pablo. La pâ”œÂ®trea fachada y los jarrones incrustados que luce son una impostaciâ”œâ”‚n del siglo XVIII, cuando se recubriâ”œâ”‚ con piedra el ladrillo de la fâ”œÃ­brica original. Fuente visual: "Aragâ”œâ”‚n : revista grâ”œÃ­fica de cultura aragonesa" (Aâ”œâ–’o XXVIII, Nâ”¬â•‘ 227, abril-junio 1953).', 1953, 1953, 1953, 'Anos 50', 'CASCO HISTâ”œÃ´RICO', 41.65588600, -0.88609200, '0101000020E610000053E9279CDD5AECBFBFF38B12F4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15507137488.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15507137488.webp', 'https://www.flickr.com/photos/zaragozaantigua/15507137488/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22206, 'San Pablo 1955', '"Nocturno en San Pablo", â”œâ”‚leo sobre lienzo, Josâ”œÂ® Baquâ”œÂ® Ximâ”œÂ®nez, 1955. Vista del caserâ”œÂ¡o del barrio de San Pablo, con la torre mudâ”œÂ®jar de la iglesia homâ”œâ”‚nima presidiendo rotunda el paisaje. Fuente: baqueximenez.weebly.com', 1955, 1955, 1955, 'Anos 50', 'CASCO HISTâ”œÃ´RICO', 41.65613400, -0.88619500, '0101000020E6100000791EDC9DB55BECBF97E5EB32FCD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40209712155.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40209712155.webp', 'https://www.flickr.com/photos/zaragozaantigua/40209712155/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
