INSERT INTO public.photos VALUES (22389, 'Calle Zamoray 1968', 'Chaflâ”œÃ­n entre las calles de Agustina de Aragâ”œâ”‚n (izquierda) y Josâ”œÂ® Zamoray (derecha). Fuente visual: Foto Leonardo Pâ”œÂ®rez Obis, donada por â”œÃ¼ngel Hernâ”œÃ­ndez Mostajo para www.rafaelcastillejo.com', 1968, 1968, 1968, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65473200, -0.88824100, '0101000020E610000039ECBE63786CECBF85D21742CED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22727732317.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22727732317.webp', 'https://www.flickr.com/photos/zaragozaantigua/22727732317/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22452, 'Calle General Franco 1967', 'Foto: Emilio Aure Durbâ”œÃ­n. Vista de la calle del General Franco, con la zona del Portillo al fondo. A la derecha, en el nâ”œâ•‘mero 32, cartel del Cine Monumental, inaugurado en 1933 como "Monumental Cinema" y clausurado en 1972. Fuente visual: www.facebook.com/photo.php?fbid=1802072866697326&set=...', 1967, 1967, 1967, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65493800, -0.88719100, '0101000020E6100000F3C64961DE63ECBF2E742502D5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31419929176.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31419929176.webp', 'https://www.flickr.com/photos/zaragozaantigua/31419929176/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22458, 'Iglesia de San Pablo c.1963', 'Iglesia de San Pablo. â”œÃ´leo de Juliâ”œÃ­n Borreguero. Vista de la plaza de San Pablo, con la fachada de la iglesia adornada con los aâ”œâ–’adidos del siglo XVIII que serâ”œÃ­n retirados en 1977. Fuente: www.arteinformado.com/', 1963, 1963, 1963, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65588600, -0.88609200, '0101000020E610000053E9279CDD5AECBFBFF38B12F4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31810772780.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31810772780.webp', 'https://www.flickr.com/photos/zaragozaantigua/31810772780/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22492, 'Calle del General Franco 1968', 'Imagen capturada en el adoquinado tramo inicial de la calle del General Franco, entre el colegio de los Escolapios y el inmueble del nâ”¬â•‘ 28, a la izquierda. Centra la escena la composiciâ”œâ”‚n tranviaria M59+R87 de la lâ”œÂ¡nea 5 "Venecia-Delicias" encaminada hacia la terminal de la plaza de Huesca. Tras ella, la desaparecida fachada edilicia de la manzana entre la calle de Miguel de Ara y la de Ramâ”œâ”‚n y Cajal. A la derecha extrema sobresale el torreâ”œâ”‚n occidental del palacio de la Audiencia, y algunos de los anuncios comerciales que culminaban el arranque de la desaparecida manzana entre la calle de Cerdâ”œÃ­n y la de las Escuelas Pâ”œÂ¡as. Fuente visual: foto Charles F. Firminger en "30937 Transport Photograph Database".', 1968, 1968, 1968, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65473500, -0.88642500, '0101000020E6100000E86A2BF6975DECBFF645425BCED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/46933109132.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/46933109132.webp', 'https://www.flickr.com/photos/zaragozaantigua/46933109132/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22568, 'Rastro del Mercado 1975', 'Archivo Municipal Zaragoza. Gerardo Sancho Ramo. Junio 1975. "Rastro del Mercado." Zaragoza 100%: estâ”œÃ­ pegando un sol enorme, pero no por ello hay que buscar la sombra: con ponerse un periâ”œâ”‚dico en la cabeza, vale. Imagen del rastro, secciâ”œâ”‚n sables, braseros, candelabros y quincalla varia, en el entorno de la puerta principal de acceso al Mercado Central, inmediata a la calle Cerdâ”œÃ­n, calle a la que le quedaba apenas una legislatura de vida.', 1975, 1975, 1975, 'Anos 70', 'CASCO HISTâ”œÃ´RICO', 41.65559900, -0.88345500, '0101000020E6100000139B8F6B4345ECBF292504ABEAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15246198251.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15246198251.webp', 'https://www.flickr.com/photos/zaragozaantigua/15246198251/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
